solutions.javascript:
// Solution
function portForwardingBugFixer(portMappings) {
  let result = [];
  let containerPortMap = {};
  for (let mapping of portMappings) {
    let container = mapping.split(':')[0];
    let port = mapping.split(':')[1];
    if (!containerPortMap[container]) {
      containerPortMap[container] = {};
    }
    containerPortMap[container][port] = true;
  }
  for (let container in containerPortMap) {
    for (let port in containerPortMap[container]) {
      result.push(port + ':' + container);
    }
  }
  return result;
}

