class Solution:
  def portForwardingBugFixer(self, port_mappings):
    result = []
    container_port_map = {}
    for mapping in port_mappings:
      container, port = mapping.split(':')
      if container not in container_port_map:
        container_port_map[container] = {}
      container_port_map[container][port] = True
    for container in container_port_map:
      for port in container_port_map[container]:
        result.append(port + ':' + container)
    return result;
